#!/usr/bin/env python3
"""memory_writeback.py — persist /ork:assess scores to the memory KG.

Closes orchestkit#1887. Headless writeback step that runs after Phase 8
(final report) when an assessment.json with composite + per-dimension
scores exists.

Mirrors `Yonatan-HQ/hq-ext-plugin#194` pattern. The shell-script → MCP
plumbing was unblocked by `yg-mcp-core 0.3.0` (Yonatan-HQ/core#993).

Three exit-0 "skip" paths (none are errors):
  - signal absent: no composite score in assessment.json
  - yg-mcp-core not importable (orchestkit is public, yg-mcp-core is HQ-private)
  - memory MCP unreachable

Tool stack (yg-mcp-core>=0.3.0):
  - mcp_core.client.probe("memory")
  - mcp_core.client.call_tool("memory", "create_entities", {entities: [...]})

Usage:
  memory_writeback.py <assessment-dir> [--entity-type TYPE]

  <assessment-dir> must contain:
    assessment.json   {composite, scores: {dim: 0-10, ...}, summary, ...}

Outputs:
  <assessment-dir>/memory-writeback.json    handoff JSON

Exit codes:
  0   success, auto-skip per signals, OR MCP/dep unreachable (WARN only)
  1   pre-flight failure (missing args, assessment dir / required files absent)
  2   memory MCP returned an error AFTER probe succeeded (real error)
"""

import argparse
import json
import os
import sys
from datetime import UTC, datetime
from pathlib import Path
from typing import Any

# Override at test time via env var.
DEFAULT_MCP_SERVER = os.environ.get("ORK_MEMORY_MCP_SERVER", "memory")


# ---------------------------------------------------------------------------
# CLI
# ---------------------------------------------------------------------------


def _parse_args(argv: list[str] | None = None) -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Write /ork:assess scores to the memory MCP knowledge graph.",
    )
    parser.add_argument(
        "assessment_dir",
        type=Path,
        help="Assessment directory containing assessment.json.",
    )
    parser.add_argument(
        "--entity-type",
        default="assessment",
        help="entityType for the writeback (default: 'assessment').",
    )
    return parser.parse_args(argv)


# ---------------------------------------------------------------------------
# entity construction (pure)
# ---------------------------------------------------------------------------


def _composite(assessment: dict[str, Any]) -> float | None:
    value = assessment.get("composite")
    if isinstance(value, (int, float)):
        return float(value)
    return None


def _entity_name(assessment: dict[str, Any], assessment_dir: Path) -> str:
    """Derive a stable entity name from the assessment.

    Order of preference: explicit `entity_name` → `slug` → directory basename.
    Always suffixed with the timestamp so re-runs don't collide.
    """
    explicit = assessment.get("entity_name") or assessment.get("slug")
    base = (
        explicit.strip() if isinstance(explicit, str) and explicit.strip() else assessment_dir.name
    )
    ts = assessment.get("timestamp") or datetime.now(UTC).strftime("%Y-%m-%dT%H-%M-%SZ")
    return f"{base}@{ts}"


def build_entity(
    assessment: dict[str, Any],
    assessment_dir: Path,
    entity_type: str,
) -> dict[str, Any]:
    """Construct the create_entities payload from assessment.json.

    Observations capture: composite, every dimension score, and the
    1-line summary if present. All as strings — the memory MCP's
    observations field is `list[str]`.
    """
    composite = _composite(assessment)
    if composite is None:
        raise ValueError("assessment.json has no composite score")

    name = _entity_name(assessment, assessment_dir)
    observations: list[str] = [f"composite={composite:.2f}"]

    scores = assessment.get("scores", {})
    if isinstance(scores, dict):
        # Sort for deterministic output — the order in which dimensions
        # appear in observations is the order operators see them.
        for dim, score in sorted(scores.items()):
            if isinstance(score, (int, float)):
                observations.append(f"{dim}={float(score):.2f}")

    summary = assessment.get("summary")
    if isinstance(summary, str) and summary.strip():
        observations.append(f"summary: {summary.strip()}")

    topic = assessment.get("topic")
    if isinstance(topic, str) and topic.strip():
        observations.append(f"topic: {topic.strip()}")

    return {
        "name": name,
        "entityType": entity_type,
        "observations": observations,
    }


# ---------------------------------------------------------------------------
# handoff JSON
# ---------------------------------------------------------------------------


def _write_handoff(handoff_path: Path, payload: dict[str, Any]) -> None:
    handoff_path.write_text(json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8")


def _write_skip(handoff_path: Path, reason: str) -> None:
    _write_handoff(handoff_path, {"status": "skipped", "skip_reason": reason})


# ---------------------------------------------------------------------------
# main
# ---------------------------------------------------------------------------


def main(argv: list[str] | None = None) -> int:
    args = _parse_args(argv)
    assessment_dir: Path = args.assessment_dir
    entity_type: str = args.entity_type

    if not assessment_dir.is_dir():
        print(
            f"memory_writeback: assessment dir not found: {assessment_dir}",
            file=sys.stderr,
        )
        return 1

    assessment_path = assessment_dir / "assessment.json"
    handoff_path = assessment_dir / "memory-writeback.json"

    if not assessment_path.is_file():
        print(
            f"memory_writeback: assessment.json missing at {assessment_path}",
            file=sys.stderr,
        )
        return 1

    try:
        assessment = json.loads(assessment_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError) as exc:
        print(f"memory_writeback: cannot parse {assessment_path}: {exc}", file=sys.stderr)
        return 1

    # Signal probe — auto-skip if no composite.
    if _composite(assessment) is None:
        reason = "no composite score in assessment.json"
        print(f"memory_writeback: auto-skipped — {reason}")
        _write_skip(handoff_path, reason)
        return 0

    # MCP preflight — fail-soft on dep miss OR unreachable server.
    try:
        from mcp_core.client import (  # type: ignore[import-not-found]
            McpToolError,
            McpUnreachable,
            call_tool,
            probe,
        )
    except ImportError:
        print(
            "memory_writeback: WARN — yg-mcp-core not importable; skipping "
            "(install yg-mcp-core>=0.3.0 from pypi.yonyon.ai to enable)"
        )
        _write_skip(handoff_path, "yg-mcp-core not importable")
        return 0

    server = DEFAULT_MCP_SERVER
    if not probe(server):
        print(f"memory_writeback: WARN — {server!r} MCP unreachable; skipping")
        _write_skip(handoff_path, f"{server!r} MCP unreachable")
        return 0

    # Build entity + call create_entities.
    try:
        entity = build_entity(assessment, assessment_dir, entity_type)
    except ValueError as exc:
        # Defensive: _composite check above should preempt this. Surface drift.
        print(f"memory_writeback: ERROR — {exc}", file=sys.stderr)
        return 2

    print(
        f"memory_writeback: writing entity {entity['name']!r} "
        f"({len(entity['observations'])} observations) to {server!r}"
    )

    try:
        result = call_tool(server, "create_entities", {"entities": [entity]})
    except (McpUnreachable, McpToolError) as exc:
        print(f"memory_writeback: ERROR — {type(exc).__name__}: {exc}", file=sys.stderr)
        return 2

    _write_handoff(
        handoff_path,
        {
            "status": "fired",
            "entity_name": entity["name"],
            "entity_type": entity_type,
            "observations_count": len(entity["observations"]),
            "server": server,
            "result": result
            if isinstance(result, (dict, list, str, int, float, bool, type(None)))
            else str(result),
        },
    )
    print(f"memory_writeback: ✓ wrote entity to {server!r} KG")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
